/**
 * Compliance/treasury staff often need to download every notification
preference change recorded in the org for offline review. Returns the
same `member_audit_log` rows as the in-page Players timeline (Task
#1505) — one CSV row per (audit row × field) so multi-field saves
expand naturally — with columns: Timestamp, Member User ID, Member,
Actor, Role, Entity, Action, Field, Before, After, Reason.
Defaults to entity=`comm_prefs`; pass `?entity=all` to include every
entity recorded against members in the org.

 * @summary Org-wide CSV export of the comm_prefs audit history.
 */
export const getExportOrgCommPrefsAuditCsvUrl = (
  orgId: number,
  params?: ExportOrgCommPrefsAuditCsvParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/organizations/${orgId}/members/audit-log.csv?${stringifiedParams}`
    : `/api/organizations/${orgId}/members/audit-log.csv`;
};

export const exportOrgCommPrefsAuditCsv = async (
  orgId: number,
  params?: ExportOrgCommPrefsAuditCsvParams,
  options?: RequestInit,
): Promise<Blob> => {
  return customFetch<Blob>(getExportOrgCommPrefsAuditCsvUrl(orgId, params), {
    ...options,
    method: "GET",
  });
};

export const getExportOrgCommPrefsAuditCsvQueryKey = (
  orgId: number,
  params?: ExportOrgCommPrefsAuditCsvParams,
) => {
  return [
    `/api/organizations/${orgId}/members/audit-log.csv`,
    ...(params ? [params] : []),
  ] as const;
};

