/**
 * @summary List all scores for a tournament
 */
export const getListScoresUrl = (
  orgId: number,
  tournamentId: number,
  params?: ListScoresParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/organizations/${orgId}/tournaments/${tournamentId}/scores?${stringifiedParams}`
    : `/api/organizations/${orgId}/tournaments/${tournamentId}/scores`;
};

export const listScores = async (
  orgId: number,
  tournamentId: number,
  params?: ListScoresParams,
  options?: RequestInit,
): Promise<Score[]> => {
  return customFetch<Score[]>(getListScoresUrl(orgId, tournamentId, params), {
    ...options,
    method: "GET",
  });
};

